<template>
    <n-space justify="space-between"  class="bar" >
        <n-space :size="25">
            <n-button round class="title" @click="router.push('/')">{{ t('header.title') }}</n-button>
        </n-space>
        <n-space justify="center" :size="25">
            <n-tooltip v-for="item in midButtons" :key="item.id">
                <template #trigger>
                    <n-button size="small" ghost :type="item.type ?? 'primary'">
                        <template #icon>
                            <n-icon :color="item.color ?? '#51d6a9'">
                                <component :is="item.icon"></component>
                            </n-icon>
                        </template>
                    </n-button>
                </template>
                {{ item.tooltip ?? '' }}
            </n-tooltip>
        </n-space>
        <n-space justify="end" :size="25">
            <n-tooltip v-for="item in rightButtons" :key="item.id">
                <template #trigger>
                    <n-button size="small" ghost :type="item.type ?? 'primary'" class="header-btn" @click="item.click(item)">
                        <template #icon>
                            <n-icon v-if="item.icon || item.icon2" :color="item.color ?? '#51d6a9'">
                                <component v-if="!item.switchIcon" :is="item.icon"></component>
                                <component v-else :is="item.icon2"></component>
                            </n-icon>
                        </template>
                        {{ item.title }}
                    </n-button>
                </template>
                {{ item.tooltip ?? '' }}
            </n-tooltip>
            <n-dropdown trigger="click" :options="langOptions" @select="onLangSelect">
                <n-button size="small" ghost type="primary" class="lang-trigger" :aria-label="t('common.selectLanguage')">
                    <template #icon>
                        <n-icon>
                            <svg xmlns="http://www.w3.org/2000/svg" class="i18n-icon" viewBox="0 0 1024 1024" fill="currentColor" aria-label="i18n icon" style="width: 1rem; height: 1rem; vertical-align: middle;">
                                <path d="M379.392 460.8 494.08 575.488l-42.496 102.4L307.2 532.48 138.24 701.44l-71.68-72.704L234.496 460.8l-45.056-45.056c-27.136-27.136-51.2-66.56-66.56-108.544h112.64c7.68 14.336 16.896 27.136 26.112 35.84l45.568 46.08 45.056-45.056C382.976 312.32 409.6 247.808 409.6 204.8H0V102.4h256V0h102.4v102.4h256v102.4H512c0 70.144-37.888 161.28-87.04 210.944L378.88 460.8zM576 870.4 512 1024H409.6l256-614.4H768l256 614.4H921.6l-64-153.6H576zM618.496 768h196.608L716.8 532.48 618.496 768z"/>
                            </svg>
                        </n-icon>
                    </template>
                </n-button>
            </n-dropdown>
        </n-space>
    </n-space>
    <n-modal v-model:show="showSetting" preset="dialog" :title="t('common.settings')" :positive-text="t('common.confirm')" :negative-text="t('common.cancelAlt')" @positive-click="onSettingOk" @negative-click="onSettingCancel">
        <n-space vertical>
            {{ t('header.serviceUrl') }}<n-input v-model:value="serviceUrl" type="text" placeholder="" />
            {{ t('header.serviceToken') }}<n-input v-model:value="accessToken" type="text" placeholder="" />
        </n-space>
    </n-modal>
    <n-modal v-model:show="showContract" preset="dialog" :title="t('header.downloadSource')" >
        <n-image
            width="400"
            :src="contractImage"
        />
        <div v-if="app.locale === 'en'" style="margin-top: 10px; text-align: center;">
            Email: vjmapcom@163.com
        </div>
    </n-modal>
</template>

<script setup lang="ts">
import { Moon, Sunny, Settings } from '@vicons/ionicons5'
import { reactive, ref, computed } from 'vue';
import { useI18n } from 'vue-i18n';
import type { ButtonIconItem } from '@/types'
import { useAppStore } from "@/stores/app";
import router from '@/router';
import { i18n } from '@/i18n';
import type { LocaleId } from '@/i18n';

const { t } = useI18n();
const app = useAppStore();
const showSetting = ref(false);
const showContract = ref(false);
const serviceUrl = ref(app.serviceUrl);
const accessToken = ref(app.accessToken);
const contractImage = ref("");

const langOptions = computed(() => [
  { label: t('header.localeZh'), key: 'zh' as LocaleId },
  { label: 'English', key: 'en' as LocaleId },
]);

function onLangSelect(key: LocaleId) {
  app.setLocale(key);
  i18n.global.locale.value = key;

  const hash = window.location.hash.replace(/^#/, '')
  const qIdx = hash.indexOf('?')
  const hashPath = qIdx >= 0 ? hash.substring(0, qIdx) : hash
  const hashQuery = qIdx >= 0 ? hash.substring(qIdx + 1) : ''
  const params = new URLSearchParams(hashQuery)

  if (key === 'zh') {
    params.delete('lang')
  } else {
    params.set('lang', key)
  }

  const qs = params.toString()
  window.location.hash = '#' + hashPath + (qs ? '?' + qs : '')
}

const midButtons = reactive<ButtonIconItem[]>([]);

const rightButtons = computed<ButtonIconItem[]>(() => [
  {
    id: 'cloud',
    title: t('header.cloudTitle'),
    tooltip: t('header.cloudTooltip'),
    type: 'success',
    click: () => {
      let href = window.location.origin + window.location.pathname;
      if (href.indexOf("visual") >= 0) {
        href = href.replace("visual", "cloud");
      } else {
        href = "https://vjmap.com/app/cloud/";
      }
      if (app.locale === 'en') {
        href += '#/en';
      }
      window.open(href, '_blank');
    },
  },
  {
    id: 'source',
    title: t('header.sourceTitle'),
    tooltip: t('header.sourceTooltip'),
    type: 'success',
    click: () => {
      showContract.value = true;
    },
  },
  {
    id: 'help',
    title: t('header.help'),
    tooltip: t('header.helpTooltip'),
    type: 'success',
    click: () => {
      const href = app.locale === 'en'
        ? "https://vjmap.com/en/guide/visual.html"
        : "https://vjmap.com/guide/visual.html";
      window.open(href, '_blank');
    },
  },
  {
    id: 'setting',
    title: t('common.settings'),
    icon: Settings,
    tooltip: t('common.settings'),
    type: 'success',
    click: () => {
      showSetting.value = true;
    },
  },
  {
    id: 'home',
    title: t('header.theme'),
    icon: Moon,
    tooltip: t('header.theme'),
    type: 'success',
    switchIcon: app.lightTheme,
    icon2: Sunny,
    click: () => {
      onTheme();
    },
  },
]);


const emit = defineEmits(["onTheme"]);
const onTheme = () => {
    emit('onTheme')
}

const onSettingOk = () => {
    app.serviceUrl = serviceUrl.value;
    app.accessToken = accessToken.value;
}

const onSettingCancel = ()=> {
    serviceUrl.value = app.serviceUrl;
    accessToken.value = app.accessToken;
}

contractImage.value = "data:image/jpeg;base64,";
</script>

<style scoped>
.bar {
    margin: 3px;
}
.title {
    font-size: 1.25rem;
    line-height: 1.75rem;
    font-weight: 500;
    margin-left: 20px;
    margin-top: 0px;
}
.i18n-icon {
    color: inherit;
}
</style>
